import React from 'react'
import { colors } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import StarCheck from '../assets/StarCheck'

/** This allows the check icon to hang off the side a little, so the text seems centered */
const magicCheckIconCss = css`
  position: relative;
  margin-inline-end: 12px;
  & > * {
    position: absolute;
    top: -5px;
  }
`

export default function AssociatedUserIcon() {
  const { t } = useTranslation()

  return (
    <div className={magicCheckIconCss} title={t('person.associated-user.label')}>
      <StarCheck
        size="xs"
        color={colors.blue60}
        data-testid="associated-user-button" // keeping this button instead of icon for backward compatibility with tests
        aria-label={t('person.associated-user.label')}
      />
    </div>
  )
}
